/**
 * Gemini Gateway Unit Tests
 * Issue #106: gateway.tsテスト追加
 *
 * Tests for streaming response generation, error handling, and retry logic.
 */

import { describe, it, expect, beforeEach, vi, afterEach } from 'vitest';
import type { CoreMessage } from 'ai';

// Mock dependencies
vi.mock('@ai-sdk/google', () => ({
  createGoogleGenerativeAI: vi.fn(),
}));

vi.mock('ai', () => ({
  streamText: vi.fn(),
}));

vi.mock('@/server/lib/logger', () => ({
  logger: {
    info: vi.fn(),
    error: vi.fn(),
  },
}));

vi.mock('@/server/lib/gemini/config', () => ({
  getGeminiApiKey: vi.fn(),
  getModelId: vi.fn((model: string) => model),
}));

describe('Gemini Gateway', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.resetModules();
    vi.useRealTimers();
  });

  describe('generateStreamingResponse', () => {
    it('should throw error when API key is not configured', async () => {
      const { getGeminiApiKey } = await import('@/server/lib/gemini/config');
      vi.mocked(getGeminiApiKey).mockReturnValue(undefined);

      const { generateStreamingResponse } = await import('@/server/lib/gemini/gateway');

      const messages: CoreMessage[] = [{ role: 'user', content: 'Hello' }];

      await expect(generateStreamingResponse(messages)).rejects.toThrow(
        'Gemini API key is not configured'
      );
    });

    it('should generate streaming response successfully', async () => {
      const { getGeminiApiKey, getModelId } = await import('@/server/lib/gemini/config');
      const { createGoogleGenerativeAI } = await import('@ai-sdk/google');
      const { streamText } = await import('ai');
      const { logger } = await import('@/server/lib/logger');

      vi.mocked(getGeminiApiKey).mockReturnValue('test-api-key');
      vi.mocked(getModelId).mockImplementation((model: string) => model);

      const mockModel = vi.fn();
      vi.mocked(createGoogleGenerativeAI).mockReturnValue(mockModel as any);

      const mockResult = {
        toDataStreamResponse: () => new Response('stream data'),
      };
      vi.mocked(streamText).mockResolvedValue(mockResult as any);

      const { generateStreamingResponse } = await import('@/server/lib/gemini/gateway');

      const messages: CoreMessage[] = [
        { role: 'system', content: 'You are a helpful assistant.' },
        { role: 'user', content: 'What is WMG2027?' },
      ];

      const result = await generateStreamingResponse(messages);

      expect(result).toBe(mockResult);
      expect(createGoogleGenerativeAI).toHaveBeenCalledWith({ apiKey: 'test-api-key' });
      expect(streamText).toHaveBeenCalled();
      expect(logger.info).toHaveBeenCalledWith(
        expect.objectContaining({ latency: expect.any(Number) }),
        'Gemini response latency'
      );
    });

    it('should use custom config when provided', async () => {
      const { getGeminiApiKey, getModelId } = await import('@/server/lib/gemini/config');
      const { createGoogleGenerativeAI } = await import('@ai-sdk/google');
      const { streamText } = await import('ai');

      vi.mocked(getGeminiApiKey).mockReturnValue('test-api-key');
      vi.mocked(getModelId).mockImplementation((model: string) => model);

      const mockModel = vi.fn();
      vi.mocked(createGoogleGenerativeAI).mockReturnValue(mockModel as any);
      vi.mocked(streamText).mockResolvedValue({
        toDataStreamResponse: () => new Response(),
      } as any);

      const { generateStreamingResponse } = await import('@/server/lib/gemini/gateway');

      const messages: CoreMessage[] = [{ role: 'user', content: 'Test' }];
      const customConfig = {
        model: 'models/gemini-pro',
        maxTokens: 4096,
        temperature: 0.8,
      };

      await generateStreamingResponse(messages, customConfig);

      expect(streamText).toHaveBeenCalledWith(
        expect.objectContaining({
          maxTokens: 4096,
          temperature: 0.8,
        })
      );
    });

    it('should retry on 429 rate limit error', async () => {
      const { getGeminiApiKey, getModelId } = await import('@/server/lib/gemini/config');
      const { createGoogleGenerativeAI } = await import('@ai-sdk/google');
      const { streamText } = await import('ai');
      const { logger } = await import('@/server/lib/logger');

      vi.mocked(getGeminiApiKey).mockReturnValue('test-api-key');
      vi.mocked(getModelId).mockImplementation((model: string) => model);

      const mockModel = vi.fn();
      vi.mocked(createGoogleGenerativeAI).mockReturnValue(mockModel as any);

      const mockResult = { toDataStreamResponse: () => new Response() };

      // First call fails with 429, second succeeds
      vi.mocked(streamText)
        .mockRejectedValueOnce(new Error('429 Too Many Requests'))
        .mockResolvedValueOnce(mockResult as any);

      const { generateStreamingResponse } = await import('@/server/lib/gemini/gateway');

      const messages: CoreMessage[] = [{ role: 'user', content: 'Test' }];

      // Run timers to handle sleep
      const resultPromise = generateStreamingResponse(messages);
      await vi.advanceTimersByTimeAsync(1000);
      const result = await resultPromise;

      expect(result).toBe(mockResult);
      expect(streamText).toHaveBeenCalledTimes(2);
      expect(logger.info).toHaveBeenCalledWith(
        expect.objectContaining({ code: undefined }),
        'Retrying Gemini request...'
      );
    });

    it('should retry on 5xx server error', async () => {
      const { getGeminiApiKey, getModelId } = await import('@/server/lib/gemini/config');
      const { createGoogleGenerativeAI } = await import('@ai-sdk/google');
      const { streamText } = await import('ai');
      const { logger } = await import('@/server/lib/logger');

      vi.mocked(getGeminiApiKey).mockReturnValue('test-api-key');
      vi.mocked(getModelId).mockImplementation((model: string) => model);

      const mockModel = vi.fn();
      vi.mocked(createGoogleGenerativeAI).mockReturnValue(mockModel as any);

      const mockResult = { toDataStreamResponse: () => new Response() };

      // First call fails with 500, second succeeds
      vi.mocked(streamText)
        .mockRejectedValueOnce(new Error('500 Internal Server Error'))
        .mockResolvedValueOnce(mockResult as any);

      const { generateStreamingResponse } = await import('@/server/lib/gemini/gateway');

      const messages: CoreMessage[] = [{ role: 'user', content: 'Test' }];

      const resultPromise = generateStreamingResponse(messages);
      await vi.advanceTimersByTimeAsync(1000);
      const result = await resultPromise;

      expect(result).toBe(mockResult);
      expect(streamText).toHaveBeenCalledTimes(2);
      expect(logger.info).toHaveBeenCalledWith(
        expect.objectContaining({ code: undefined }),
        'Retrying Gemini request...'
      );
    });

    it('should throw fallback error after retry fails', async () => {
      const { getGeminiApiKey, getModelId } = await import('@/server/lib/gemini/config');
      const { createGoogleGenerativeAI } = await import('@ai-sdk/google');
      const { streamText } = await import('ai');
      const { logger } = await import('@/server/lib/logger');

      vi.mocked(getGeminiApiKey).mockReturnValue('test-api-key');
      vi.mocked(getModelId).mockImplementation((model: string) => model);

      const mockModel = vi.fn();
      vi.mocked(createGoogleGenerativeAI).mockReturnValue(mockModel as any);

      // Both calls fail
      vi.mocked(streamText)
        .mockRejectedValueOnce(new Error('429 Too Many Requests'))
        .mockRejectedValueOnce(new Error('429 Too Many Requests'));

      const { generateStreamingResponse } = await import('@/server/lib/gemini/gateway');

      const messages: CoreMessage[] = [{ role: 'user', content: 'Test' }];

      // Attach rejection handler immediately to prevent unhandled rejection
      const resultPromise = generateStreamingResponse(messages).catch(e => e);
      await vi.advanceTimersByTimeAsync(1000);

      const error = await resultPromise;
      expect(error).toBeInstanceOf(Error);
      expect(error.message).toContain('一時的に利用できません');
      expect(streamText).toHaveBeenCalledTimes(2);
      expect(logger.error).toHaveBeenCalledWith(
        expect.objectContaining({
          error: expect.objectContaining({ message: expect.any(String) }),
        }),
        'Gemini retry failed'
      );
    });

    it('should not retry on non-retryable errors', async () => {
      const { getGeminiApiKey, getModelId } = await import('@/server/lib/gemini/config');
      const { createGoogleGenerativeAI } = await import('@ai-sdk/google');
      const { streamText } = await import('ai');
      const { logger } = await import('@/server/lib/logger');

      vi.mocked(getGeminiApiKey).mockReturnValue('test-api-key');
      vi.mocked(getModelId).mockImplementation((model: string) => model);

      const mockModel = vi.fn();
      vi.mocked(createGoogleGenerativeAI).mockReturnValue(mockModel as any);

      // Fail with 400 Bad Request (not retryable)
      const badRequestError = new Error('400 Bad Request');
      vi.mocked(streamText).mockRejectedValueOnce(badRequestError);

      const { generateStreamingResponse } = await import('@/server/lib/gemini/gateway');

      const messages: CoreMessage[] = [{ role: 'user', content: 'Test' }];

      await expect(generateStreamingResponse(messages)).rejects.toThrow('400 Bad Request');
      expect(streamText).toHaveBeenCalledTimes(1);
      expect(logger.error).toHaveBeenCalledWith(
        expect.objectContaining({
          error: expect.objectContaining({ message: '400 Bad Request' }),
        }),
        'Gemini streaming error'
      );
    });

    it('should log latency on successful response', async () => {
      const { getGeminiApiKey, getModelId } = await import('@/server/lib/gemini/config');
      const { createGoogleGenerativeAI } = await import('@ai-sdk/google');
      const { streamText } = await import('ai');
      const { logger } = await import('@/server/lib/logger');

      vi.mocked(getGeminiApiKey).mockReturnValue('test-api-key');
      vi.mocked(getModelId).mockImplementation((model: string) => model);

      const mockModel = vi.fn();
      vi.mocked(createGoogleGenerativeAI).mockReturnValue(mockModel as any);
      vi.mocked(streamText).mockResolvedValue({
        toDataStreamResponse: () => new Response(),
