describe('PromptTemplateEngine', () => {
  describe('buildPrompt', () => {
    it('日本語質問に日本語ルールを適用', () => {
      const userQuery = '参加資格は？';
      const contexts: FileSearchResult[] = [];
      const locale = 'ja';

      const prompt = buildPrompt(userQuery, contexts, locale);

      expect(prompt).toContain('ワールドマスターズゲームズ2027');
      expect(prompt).toContain('公式AIアシスタント');
      expect(prompt).toContain('言語対応ルール');
      expect(prompt).toContain('ロケール設定（ja）を使用');
